@page "/settings"
@using sv_5b72cd1620cd43f58b6521b6032e96ff.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="section-icon">@section.Value.Icon</span>
                        @section.Value.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <!-- Main Content Area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast Message -->
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="alert @(_toastIsError ? "alert-danger" : "alert-success") alert-dismissible fade show toast-message" role="alert">
                    @_toastMessage
                    <button type="button" class="btn-close" @onclick="DismissToast"></button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ─── Profile Section ─── *@
@{ RenderFragment RenderProfileSection() =>
    @<section>
        <h3>Profile</h3>
        <p class="text-muted">Manage your personal information</p>
        <hr />

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_editDisplayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_editEmail" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_editBio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="avatar-preview-card">
                    <label class="form-label">Avatar Preview</label>
                    <div class="avatar-frame">
                        @if (!string.IsNullOrWhiteSpace(_editAvatarUrl))
                        {
                            <img src="@_editAvatarUrl" alt="Avatar" class="avatar-img" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">No avatar</div>
                        }
                    </div>
                    <div class="mt-2">
                        <label class="form-label small text-muted">Avatar URL</label>
                        <input type="url" class="form-control form-control-sm" @bind="_editAvatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
        </div>
    </section>;
}

@* ─── Notifications Section ─── *@
@{ RenderFragment RenderNotificationsSection() =>
    @<section>
        <h3>Notifications</h3>
        <p class="text-muted">Choose how you receive notifications</p>
        <hr />

        <div class="mb-4">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_editEmailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_editPushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications on your devices</div>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_editWeeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </label>
            </div>
        </div>

        <h5>Muted Channels</h5>
        <p class="text-muted small">Select channels to mute</p>
        <div class="row row-cols-2 row-cols-md-3 g-2 mb-4">
            @foreach (var channel in _allChannels)
            {
                var ch = channel;
                <div class="col">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="ch-@ch"
                               checked="@_editMutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="ch-@ch">#@ch</label>
                    </div>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Preferences
        </button>
    </section>;
}

@* ─── Security Section ─── *@
@{ RenderFragment RenderSecuritySection() =>
    @<section>
        <h3>Security</h3>
        <p class="text-muted">Manage your account security</p>
        <hr />

        <!-- Change Password Panel -->
        <div class="card mb-4">
            <div class="card-header d-flex align-items-center justify-content-between"
                 style="cursor: pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <strong>Change Password</strong>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="text-danger mb-2">@_passwordError</div>
                    }
                    <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="mt-1">
                        <span class="badge @(_editTwoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_editTwoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_editTwoFactorEnabled" />
                </div>
            </div>
        </div>

        @if (_securitySettings?.LastPasswordChange is not null)
        {
            <p class="text-muted small mb-4">
                Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <!-- Active Sessions -->
        <h5>Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (_securitySettings?.Sessions is not null)
                    {
                        @foreach (var session in _securitySettings.Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != _currentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevokeSession(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal fade show d-block" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted small">This will sign the device out immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </section>;
}

@* ─── Appearance Section ─── *@
