                        <label class="form-check-label" for="ch-@ch">#@ch</label>
                    </div>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Preferences
        </button>
    </section>;
}

@* ─── Security Section ─── *@
@{ RenderFragment RenderSecuritySection() =>
    @<section>
        <h3>Security</h3>
        <p class="text-muted">Manage your account security</p>
        <hr />

        <!-- Change Password Panel -->
        <div class="card mb-4">
            <div class="card-header d-flex align-items-center justify-content-between"
                 style="cursor: pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <strong>Change Password</strong>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="text-danger mb-2">@_passwordError</div>
                    }
                    <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="mt-1">
                        <span class="badge @(_editTwoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_editTwoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_editTwoFactorEnabled" />
                </div>
            </div>
        </div>

        @if (_securitySettings?.LastPasswordChange is not null)
        {
            <p class="text-muted small mb-4">
                Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <!-- Active Sessions -->
        <h5>Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (_securitySettings?.Sessions is not null)
                    {
                        @foreach (var session in _securitySettings.Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != _currentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevokeSession(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal fade show d-block" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted small">This will sign the device out immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </section>;
}

@* ─── Appearance Section ─── *@
@{ RenderFragment RenderAppearanceSection() =>
    @<section>
        <h3>Appearance</h3>
        <p class="text-muted">Customize how the app looks</p>
        <hr />

        <div class="row">
            <div class="col-md-7">
                <!-- Theme -->
                <div class="mb-4">
                    <label class="form-label fw-bold">Theme</label>
                    <div class="d-flex gap-3">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            var t = theme;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="theme-@t"
                                       value="@t" checked="@(_editTheme == t)"
                                       @onchange="() => _editTheme = t" />
                                <label class="form-check-label" for="theme-@t">@t</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Font Size -->
                <div class="mb-4">
                    <label class="form-label fw-bold">Font Size</label>
                    <div class="d-flex gap-3">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            var s = size;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="fs-@s"
                                       value="@s" checked="@(_editFontSize == s)"
                                       @onchange="() => _editFontSize = s" />
                                <label class="form-check-label" for="fs-@s">@s</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <label class="form-label fw-bold">Language</label>
                    <select class="form-select" style="max-width: 280px;" @bind="_editLanguage">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                        <option value="Portuguese">Portuguese</option>
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_editCompactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-5">
                <label class="form-label fw-bold">Preview</label>
                <div class="preview-box @GetPreviewThemeClass()" style="@GetPreviewFontStyle()">
                    <div class="preview-header" style="@GetPreviewPadding()">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body" style="@GetPreviewPadding()">
                        <p style="margin-bottom: 0.5rem;">This is a preview of your selected appearance settings.</p>
                        <span class="preview-badge">@_editTheme Theme</span>
                        <span class="preview-badge">@_editFontSize Font</span>
                        @if (_editCompactMode)
                        {
                            <span class="preview-badge">Compact</span>
                        }
                        <div class="mt-2 text-muted" style="font-size: 0.85em;">Language: @_editLanguage</div>
                    </div>
                </div>
            </div>
        </div>
    </section>;
}

@code {
    // ── Section definitions ──
    private record SectionInfo(string Label, string Icon);
    private readonly Dictionary<string, SectionInfo> _sections = new()
    {
        ["profile"] = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"] = new("Security", "🔒"),
        ["appearance"] = new("Appearance", "🎨"),
    };

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastIsError;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";

    // ── Notification state ──
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = new();
    private readonly List<string> _allChannels = InMemorySettingsService.GetAllChannels();

    // ── Security state ──
    private SecuritySettings? _securitySettings;
    private bool _editTwoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "sess-1";

    // ── Appearance state ──
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        PopulateProfileFields(profile);

        var notif = notifTask.Result;
        _editEmailNotifications = notif.EmailNotifications;
        _editPushNotifications = notif.PushNotifications;
        _editWeeklyDigest = notif.WeeklyDigest;
        _editMutedChannels = new HashSet<string>(notif.MutedChannels);

        _securitySettings = securityTask.Result;
        _editTwoFactorEnabled = _securitySettings.TwoFactorEnabled;

        var appearance = appearanceTask.Result;
        _editTheme = appearance.Theme;
        _editFontSize = appearance.FontSize;
        _editLanguage = appearance.Language;
        _editCompactMode = appearance.CompactMode;
    }

    private void PopulateProfileFields(UserProfile profile)
    {
        _editDisplayName = profile.DisplayName;
        _editEmail = profile.Email;
        _editAvatarUrl = profile.AvatarUrl;
        _editBio = profile.Bio;
    }

    // ── Profile actions ──
    private async Task SaveProfile()
    {
        _saving = true;
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            PopulateProfileFields(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notification actions ──
    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _editMutedChannels.Add(channel);
        else
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, _editMutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved!");
    }

    // ── Security actions ──
    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully!");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ── Appearance actions ──
    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved!");
    }

    private string GetPreviewThemeClass() => _editTheme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewFontStyle() => _editFontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private string GetPreviewPadding() => _editCompactMode ? "padding: 0.4rem 0.75rem;" : "padding: 0.75rem 1rem;";

    // ── Helpers ──
    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
    }

    private void DismissToast() => _toastMessage = null;
}
